import os
import json
import time
import hashlib
from datetime import datetime, timedelta
from flask import Flask, request, jsonify

class DiskCache:
    def __init__(self, cache_dir="cache", default_ttl=3600):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        os.makedirs(cache_dir, exist_ok=True)
    
    def _get_cache_key(self, url, params=None):
        key_string = f"{url}_{json.dumps(params, sort_keys=True) if params else ''}"
        return hashlib.md5(key_string.encode()).hexdigest()
    
    def _is_expired(self, timestamp, ttl):
        return time.time() > timestamp + ttl
    
    def get(self, url, params=None):
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        if not os.path.exists(cache_file):
            return None
        
        try:
            with open(cache_file, 'r') as f:
                data = json.load(f)
            
            if self._is_expired(data['timestamp'], data['ttl']):
                os.remove(cache_file)
                return None
            
            return data['data']
        except (json.JSONDecodeError, KeyError):
            return None
    
    def set(self, url, data, params=None, ttl=None):
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        ttl = ttl or self.default_ttl
        
        cache_data = {
            'data': data,
            'timestamp': time.time(),
            'ttl': ttl
        }
        
        with open(cache_file, 'w') as f:
            json.dump(cache_data, f)

app = Flask(__name__)
cache = DiskCache(default_ttl=3600)

@app.route('/api/data')
def get_data():
    url = request.args.get('url', '')
    params = request.args.get('params')
    
    if params:
        try:
            params = json.loads(params)
        except json.JSONDecodeError:
            params = None
    
    cached_data = cache.get(url, params)
    
    if cached_data:
        return jsonify(cached_data)
    
    # Simulate expensive API call
    response_data = {
        'timestamp': datetime.now().isoformat(),
        'data': [i for i in range(1000)],
        'metadata': {
            'source': url,
            'processed': True,
            'nested': {
                'items': ['a', 'b', 'c'],
                'count': 3
            }
        }
    }
    
    cache.set(url, response_data, params)
